type Base = ModalProps & { text?: string };

const RenderBase: FC<Base> = props => {
  const { text = '点我', visible: visibleInProps, ...modalProps } = props;
  const [visible, setVisible] = useState<boolean>(Boolean(visibleInProps));
  return (
    <div style={{ display: 'inline-block' }}>
      <Dialog
        title="标题"
        description="这是描述这是描述这是描述这是描述这是描述这是描述这是描述这是描述这是描述这是描述"
        visible={visible}
        centered
        destroyOnClose
        onOk={() => setVisible(false)}
        onCancel={() => setVisible(false)}
        {...modalProps}
      >
        <div>
          这是内容部分，这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分
        </div>
      </Dialog>
      <Button style={{ marginRight: 10 }} onClick={() => setVisible(true)} type="primary">
        {text}
      </Button>
    </div>
  );
};

const RenderLoading: FC<any> = () => {
  const [visible, setVisible] = React.useState<boolean>(false);
  const [loading, setLoading] = React.useState<boolean>(false);
  return (
    <div style={{ display: 'inline-block' }}>
      <Dialog
        title="标题 - 点击确认后等待 3s 后关闭"
        description="这是描述这是描述这是描述这是描述这是描述这是描述这是描述这是描述这是描述这是描述"
        visible={visible}
        centered
        destroyOnClose
        confirmLoading={loading}
        onOk={() => {
          setLoading(true);
          setTimeout(() => {
            setLoading(false);
            setVisible(false);
          }, 3000);
        }}
        onCancel={() => setVisible(false)}
      >
        <div>
          这是内容部分，这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分这是内容部分
        </div>
      </Dialog>
      <Button onClick={() => setVisible(true)}>点击确认后 等待3s </Button>
    </div>
  );
};

