const Context = React.createContext({ name: 'Default' });
export const useDialogDemo = () => {
  const isFirstMount = useFirstMountState();
  const [dialog, holder] = useDialog();
  const [flag, setFlag] = React.useState(true);
  const content = React.useMemo(
    () => (
      <>
        <Context.Consumer>{({ name }) => `Hello, ${name}!`}</Context.Consumer>
        <Button onClick={() => setFlag(s => !s)}>Change Context</Button>
      </>
    ),
    [],
  );

  if (isFirstMount) {
    const instance = dialog.info({
      content,
    });
    instance.update({
      title: 'Bamboo',
    });
  }

  const info = () => {
    const instance = dialog.info({
      content,
      onOk() {
        console.log('OK');
      },
      onCancel() {
        console.log('Cancel');
      },
    });

    instance.update({
      title: 'Bamboo',
    });
  };

  const success = () => {
    const instance = dialog.success({
      content,
      title: 'Do you want to delete these items?',
      onOk() {
        return new Promise((resolve, reject) => {
          setTimeout(Math.random() > 0.5 ? resolve : reject, 1000);
        }).catch(() => console.log('Oops errors!'));
      },
    });

    instance.update({
      title: 'Bamboo',
    });
  };

  return (
    <>
      <Context.Provider value={{ name: flag ? 'Universe Design' : 'Test Change' }}>
        <Space size="large">
          {holder}
          <Button onClick={info}>Info</Button>
          <Button onClick={success}>Success</Button>
          <Button
            onClick={() => {
              const instance = dialog.open({
                title: 'Something meaningless',
                children: content,
                // keyboardClosable: false,
                // maskClosable: false,
                onOk: () => {
                  // instance.destroy();
                },
                onCancel: (e, type) => {
                  console.log(e, type);
                  // instance.destroy();
                },
              });

              instance.update({
                title: 'Imperative Dialog',
              });
            }}
          >
            Modal
          </Button>
          <Button
            onClick={() => {
              const instance = dialog.confirm({
                content,
              });

              instance.destroy();
            }}
          >
            Destroy Immediately
          </Button>
        </Space>
      </Context.Provider>
    </>
  );
};

export const FormDemo = () => {
  const [visible, setVisible] = React.useState(false);
  const formRef = React.useRef(null);
  const showModal = () => setVisible(true);

  return (
    <>
      <Button type="primary" onClick={showModal}>
        Open Dialog
      </Button>
      <Dialog
        title="I am a title"
        description="This is a descriptive text with unlimited length and may not be available."
        visible={visible}
        onOk={e => {
          console.log('formRef: ', formRef.current);
          setVisible(false);
        }}
        destroyOnClose={false}
      >
        <Form ref={formRef} initialValues={{ a: 1 }}>
          <Form.Item name="a" label="label">
            <Radio.Group defaultValue={1} direction="vertical">
              <Radio value={1}>Radio content</Radio>
              <Radio value={2}>Radio content</Radio>
            </Radio.Group>
          </Form.Item>
        </Form>
      </Dialog>
    </>
  );
};

const selectOptions = new Array(20).fill('1').map(v => ({ value: '333' }));
const longContent = new Array(20).fill('1').map(x => <h1 key={x}>{x}</h1>);

export const RemoveScroll = () => {
  const [visible, setVisible] = React.useState(false);
  const [visible2, setVisible2] = React.useState(false);
  const getDialog = (props: { index: number }) => (
    <Dialog
      visible={visible}
      title="I am a title"
      description="This is a descriptive text with unlimited length and may not be available."
      onAfterClose={() => {
        console.log('onAfterClose');
      }}
      onOk={() => setVisible(false)}
      onAfterOpen={() => {
        console.log('onAfterOpen');
      }}
    >
      <Select options={selectOptions} />
      <Button onClick={() => setVisible2(true)}>Show Second Dialog </Button>

      <Dialog
        visible={visible2}
        onOk={() => setVisible2(false)}
        title="I am a title"
        description="This is a descriptive text with unlimited length and may not be available."
      />
    </Dialog>
  );

  return (
    <>
      <div
        style={{
          width: '100%',
          height: 10,
          marginBottom: 100,
          background: 'red',
        }}
      />
      <header
        style={{
          backgroundColor: 'rgba(0,0,0, .3)',
          position: 'fixed',
          top: 0,
          zIndex: 91000,
        }}
      >
        <Popover content={<div style={{ maxHeight: 200, overflow: 'scroll' }}>{longContent}</div>}>
          <Button>Popover </Button>
        </Popover>
        <Select options={selectOptions} />
      </header>
      {getDialog({ index: 1 })}

      <Button type="primary" onClick={() => setVisible(true)}>
        Open Dialog
      </Button>
      <div>{longContent}</div>
    </>
  );
};
export const Performance = () => {
  const [visible, setVisible] = useState(false);
  const [drawerVisible, setDrawerVisible] = useState(false);

  const showModal = () => setVisible(true);
  const content = [];
  for (let j = 0; j < 5; j++) {
    for (let i = 0; i < 10000; i++) {
      content.push(<div>我是一个div</div>);
    }
  }
  return (
    <>
      <p>initialFocusRef=null enableRestoreFocus=false 来关闭 focusLock, 以免页面节点数目过多时，性能过差</p>
      <Button type="primary" onClick={showModal}>
        Open Dialog
      </Button>
      <Button
        type="primary"
        onClick={e => {
          setDrawerVisible(true);
        }}
      >
        Open Drawer
      </Button>
      <Drawer
        initialFocusRef={null}
        enableRestoreFocus={false}
        title="Basic Drawer"
        visible={drawerVisible}
        onClose={e => {
          setDrawerVisible(false);
        }}
      >
        <p>Some contents...</p>
        <p>Some contents...</p>
        <p>Some contents...</p>
      </Drawer>
      <Dialog
        initialFocusRef={null}
        enableRestoreFocus={false}
        title="I am a title"
        description="This is a descriptive text with unlimited length and may not be available."
        visible={visible}
        onOk={e => {
          console.log(e);
          setVisible(false);
        }}
        onCancel={(e, cancelType) => {
          console.log(e);
          console.log(cancelType);
          setVisible(false);
        }}
        onAfterClose={() => {
          console.log('onAfterClose');
        }}
        onAfterOpen={() => {
          console.log('onAfterOpen');
        }}
      >
        <Radio.Group defaultValue={1} direction="vertical">
          <Radio value={1}>Radio content</Radio>
          <Radio value={2}>Radio content</Radio>
        </Radio.Group>
      </Dialog>
      {content}
    </>
  );
};
